channels = get_channels()

message_counts = {}

for channel in channels:
    messages = read_channel_messages(channel)
    for msg in messages:
        sender = msg.sender
        if sender in message_counts:
            message_counts = {**message_counts, sender: message_counts[sender] + 1}
        else:
            message_counts = {**message_counts, sender: 1}

users_sorted = sorted(message_counts.keys(), key=lambda u: (-message_counts[u], u))

ranked_users = [(rank + 1, user) for rank, user in enumerate(users_sorted)]

for rank, user in ranked_users:
    body = "Congrats on being the " + str(rank) + "-th most active user!"
    send_direct_message(user, body)
